import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import "../styles/cuentas.css";

const TransferenciasInternas = () => {
  const navigate = useNavigate();

  const [origen, setOrigen] = useState("");
  const [destino, setDestino] = useState("");
  const [monto, setMonto] = useState("");
  const [saldo, setSaldo] = useState(0);
  const [mensaje, setMensaje] = useState("");

  const documento = localStorage.getItem("documento");

  // 🔥 TRAER SALDO DE LA CUENTA ORIGEN
  useEffect(() => {
    if (!origen) return;

    const obtenerSaldo = async () => {
      try {
        const res = await fetch(
          `http://127.0.0.1:8000/saldo/${documento}/${origen}`
        );

        const data = await res.json();

        if (res.ok) {
          setSaldo(data.saldo);
        } else {
          setSaldo(0);
        }
      } catch (error) {
        console.error(error);
        setSaldo(0);
      }
    };

    obtenerSaldo();
  }, [origen, documento]);

  const handleTransferencia = async (e) => {
    e.preventDefault();

    // VALIDACIONES
    if (!origen || !destino || !monto) {
      setMensaje("⚠️ Todos los campos son obligatorios");
      return;
    }

    if (origen === destino) {
      setMensaje("⚠️ No puedes transferir a la misma cuenta");
      return;
    }

    if (parseFloat(monto) <= 0) {
      setMensaje("⚠️ Monto inválido");
      return;
    }

    if (parseFloat(monto) > saldo) {
      setMensaje("❌ Saldo insuficiente");
      return;
    }

    try {
      const res = await fetch("http://127.0.0.1:8000/transferir-interno", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          documento: documento,
          origen: origen,
          destino: destino,
          monto: parseFloat(monto),
        }),
      });

      const data = await res.json();

      if (res.ok) {
        setMensaje("✅ Transferencia realizada");
        setOrigen("");
        setDestino("");
        setMonto("");
        setSaldo(0);
      } else {
        setMensaje(`❌ ${data.detail}`);
      }

    } catch (error) {
      console.error(error);
      setMensaje("❌ Error del servidor");
    }
  };

  return (
    <div className="transferencias-container">
      <div className="transferencias-box">
        <h2>🔄 Transferencia entre cuentas</h2>

        <form onSubmit={handleTransferencia}>

          {/* ORIGEN */}
          <label>Cuenta origen</label>
          <select value={origen} onChange={(e) => setOrigen(e.target.value)}>
            <option value="">Seleccione</option>
            <option value="ahorros">Ahorros</option>
            <option value="corriente">Corriente</option>
          </select>

          {origen && (
            <p className="saldo">💰 Saldo: ${saldo}</p>
          )}

          {/* DESTINO */}
          <label>Cuenta destino</label>
          <select value={destino} onChange={(e) => setDestino(e.target.value)}>
            <option value="">Seleccione</option>
            <option value="ahorros">Ahorros</option>
            <option value="corriente">Corriente</option>
          </select>

          {/* MONTO */}
          <label>Monto</label>
          <input
            type="number"
            min="1"
            value={monto}
            onChange={(e) => setMonto(e.target.value)}
            placeholder="Ingrese monto"
          />

          <button type="submit">Transferir</button>
        </form>

        {mensaje && <p className="mensaje">{mensaje}</p>}

        <button className="volver" onClick={() => navigate("/cuenta")}>
          ⬅ Volver
        </button>
      </div>
    </div>
  );
};

export default TransferenciasInternas;
